import React, { useState } from 'react';
import { GoogleGenAI } from '@google/genai';

const GeminiBuddy: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [query, setQuery] = useState('');
  const [response, setResponse] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const handleAsk = async () => {
    if (!query.trim()) return;
    setLoading(true);
    setResponse(null);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const res = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `You are the Zoomer's Lit Lab AI Buddy. Keep your answers "lit", helpful, and bite-sized. Question: ${query}`,
        config: {
          systemInstruction: "Expert, cool, and concise tutor for students in Bangladesh and globally."
        }
      });
      setResponse(res.text || "No response generated.");
    } catch (err) {
      setResponse("My AI circuits are fried! Try again in a sec.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <>
      <button 
        onClick={() => setIsOpen(true)}
        className="fixed bottom-6 right-6 z-50 bg-green-500 hover:bg-green-400 text-black p-4 rounded-full shadow-lg shadow-green-500/20 transition-all transform hover:scale-110 flex items-center justify-center border-2 border-black"
      >
        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" />
        </svg>
      </button>

      {isOpen && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-[60] flex items-center justify-center p-4">
          <div className="cyber-card w-full max-w-lg rounded-2xl overflow-hidden border-green-500/50">
            <div className="bg-green-900/20 p-4 border-b border-green-500/30 flex justify-between items-center">
              <h2 className="font-orbitron font-bold text-green-400 flex items-center space-x-2">
                <span className="w-2 h-2 bg-green-500 rounded-full animate-ping"></span>
                <span>AI STUDY BUDDY</span>
              </h2>
              <button onClick={() => setIsOpen(false)} className="text-gray-400 hover:text-white">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
            </div>

            <div className="p-6">
              <div className="mb-4 h-64 overflow-y-auto scrollbar-hide bg-black/40 rounded-xl p-4 border border-green-500/10">
                {response ? (
                  <p className="text-green-50 text-sm leading-relaxed whitespace-pre-wrap">{response}</p>
                ) : loading ? (
                  <div className="flex flex-col items-center justify-center h-full space-y-4">
                    <div className="w-10 h-10 border-2 border-green-500 border-t-transparent rounded-full animate-spin"></div>
                    <p className="text-green-500/60 font-orbitron text-xs animate-pulse">THINKING...</p>
                  </div>
                ) : (
                  <p className="text-gray-500 text-center italic mt-12">Ask me about Study Hacks, Physics, Math, or anything Lit!</p>
                )}
              </div>

              <div className="flex space-x-2">
                <input 
                  type="text" 
                  value={query}
                  onChange={(e) => setQuery(e.target.value)}
                  onKeyPress={(e) => e.key === 'Enter' && handleAsk()}
                  placeholder="Ask your AI Buddy..."
                  className="flex-1 bg-black/60 border border-green-500/30 rounded-xl px-4 py-2 text-green-50 focus:outline-none focus:border-green-500 transition-colors"
                />
                <button 
                  onClick={handleAsk}
                  disabled={loading}
                  className="bg-green-500 hover:bg-green-400 text-black px-4 py-2 rounded-xl font-bold font-orbitron disabled:opacity-50"
                >
                  SEND
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </>
  );
};

export default GeminiBuddy;

