import React, { useState } from 'react';
import { Quiz } from '../types';

interface Props {
  quiz: Quiz;
  onClose: () => void;
}

const QuizPlayer: React.FC<Props> = ({ quiz, onClose }) => {
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [selectedOption, setSelectedOption] = useState<number | null>(null);
  const [isAnswered, setIsAnswered] = useState(false);
  const [score, setScore] = useState(0);
  const [showResult, setShowResult] = useState(false);

  const currentQuestion = quiz.questions[currentQuestionIndex];

  const handleOptionClick = (index: number) => {
    if (isAnswered) return;
    setSelectedOption(index);
    setIsAnswered(true);

    if (index === currentQuestion.correctAnswer) {
      setScore(prev => prev + 1);
    }
  };

  const handleNext = () => {
    if (currentQuestionIndex < quiz.questions.length - 1) {
      setCurrentQuestionIndex(prev => prev + 1);
      setSelectedOption(null);
      setIsAnswered(false);
    } else {
      setShowResult(true);
    }
  };

  const resetQuiz = () => {
    setCurrentQuestionIndex(0);
    setSelectedOption(null);
    setIsAnswered(false);
    setScore(0);
    setShowResult(false);
  };

  return (
    <div className="fixed inset-0 bg-black/95 backdrop-blur-md z-[70] flex items-center justify-center p-4">
      <div className="cyber-card w-full max-w-2xl rounded-3xl overflow-hidden border-cyan-500/30 flex flex-col max-h-[90vh]">
        {/* Header */}
        <div className="bg-cyan-950/20 p-6 border-b border-cyan-400/20 flex justify-between items-center">
          <div>
            <h2 className="font-orbitron font-bold text-cyan-400 text-lg uppercase tracking-wider">{quiz.title}</h2>
            <p className="text-[10px] text-cyan-400/60 font-bold tracking-widest uppercase">
              Question {currentQuestionIndex + 1} of {quiz.questions.length}
            </p>
          </div>
          <button onClick={onClose} className="text-gray-400 hover:text-white transition-colors">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        <div className="p-8 overflow-y-auto scrollbar-hide flex-1">
          {!showResult ? (
            <div className="space-y-8">
              {/* Question Text */}
              <h3 className="text-xl md:text-2xl font-bold text-white leading-tight">
                {currentQuestion.text}
              </h3>

              {/* Options */}
              <div className="grid grid-cols-1 gap-4">
                {currentQuestion.options.map((option, index) => {
                  let buttonClass = "w-full text-left p-4 rounded-xl border transition-all flex items-center justify-between group ";

                  if (!isAnswered) {
                    buttonClass += "bg-black/40 border-cyan-400/20 hover:border-cyan-400 hover:bg-cyan-400/5 text-gray-300";
                  } else {
                    if (index === currentQuestion.correctAnswer) {
                      buttonClass += "bg-green-500/20 border-green-500 text-green-400 shadow-[0_0_15px_rgba(34,197,94,0.2)]";
                    } else if (index === selectedOption) {
                      buttonClass += "bg-red-500/20 border-red-500 text-red-400 shadow-[0_0_15px_rgba(239,68,68,0.2)]";
                    } else {
                      buttonClass += "bg-black/20 border-gray-800 text-gray-600 opacity-50";
                    }
                  }

                  return (
                    <button 
                      key={index}
                      onClick={() => handleOptionClick(index)}
                      disabled={isAnswered}
                      className={buttonClass}
                    >
                      <span className="font-medium">{option}</span>
                      {isAnswered && index === currentQuestion.correctAnswer && (
                        <svg className="w-5 h-5 text-green-500" fill="currentColor" viewBox="0 0 20 20">
                          <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
                        </svg>
                      )}
                    </button>
                  );
                })}
              </div>

              {/* Feedback */}
              {isAnswered && (
                <div className="p-4 rounded-xl bg-cyan-950/10 border border-cyan-400/10 animate-fadeIn">
                  <p className="text-xs font-bold text-cyan-400 uppercase tracking-widest mb-1">Expert Explanation</p>
                  <p className="text-sm text-gray-400 leading-relaxed italic">
                    "{currentQuestion.explanation}"
                  </p>
                </div>
              )}
            </div>
          ) : (
            <div className="text-center py-12 space-y-6">
              <div className="relative inline-block">
                <svg className="w-32 h-32 text-cyan-500 mx-auto" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
                </svg>
                <div className="absolute inset-0 bg-cyan-500/20 blur-2xl rounded-full"></div>
              </div>
              <div>
                <h2 className="text-3xl font-orbitron font-bold text-white uppercase tracking-tighter">Lab Results Ready</h2>
                <p className="text-gray-400 mt-2">You cleared {score} out of {quiz.questions.length} bytes of data.</p>
              </div>
              <div className="text-5xl font-orbitron font-bold text-cyan-400">
                {Math.round((score / quiz.questions.length) * 100)}%
              </div>
              <div className="pt-8 flex flex-col md:flex-row gap-4 justify-center">
                <button 
                  onClick={resetQuiz}
                  className="px-8 py-3 bg-cyan-500 text-black font-orbitron font-bold rounded-xl hover:bg-cyan-400 transition-all shadow-lg shadow-cyan-500/20"
                >
                  RETRY LAB
                </button>
                <button 
                  onClick={onClose}
                  className="px-8 py-3 bg-gray-900 text-cyan-400 font-orbitron font-bold rounded-xl border border-cyan-400/20 hover:border-cyan-400 transition-all"
                >
                  CLOSE TERMINAL
                </button>
              </div>
            </div>
          )}
        </div>

        {/* Footer */}
        {!showResult && (
          <div className="p-6 bg-cyan-950/10 border-t border-cyan-400/10 flex justify-end">
            <button
              onClick={handleNext}
              disabled={!isAnswered}
              className="px-8 py-3 bg-cyan-600/80 disabled:opacity-30 disabled:cursor-not-allowed hover:bg-cyan-500 text-white font-orbitron font-bold rounded-xl transition-all glow-button"
            >
              {currentQuestionIndex === quiz.questions.length - 1 ? 'FINISH' : 'NEXT SECTOR'}
            </button>
          </div>
        )}
      </div>
      <style>{`
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(10px); }
          to { opacity: 1; transform: translateY(0); }
        }
        .animate-fadeIn { animation: fadeIn 0.4s ease-out; }
      `}</style>
    </div>
  );
};

export default QuizPlayer;

