export default App;

import React from 'react';

export type ResourceCategory = 'Physics' | 'Chemistry' | 'Biology' | 'Math' | 'Bangla' | 'English' | 'ICT' | 'Quizzes';

export type ResourceSubCategory = 'Quiz' | 'Formula' | 'Blog' | 'Lit hack';

export interface Resource {
  id: string;
  title: string;
  description: string;
  category: Exclude<ResourceCategory, 'Quizzes'>;
  subCategory: ResourceSubCategory;
  chapter?: string;
  paper?: '1st' | '2nd';
  link: string;
  thumbnail?: string;
  tags: string[];
  dateAdded: string;
}

export interface VideoResource extends Resource {
  youtubeId: string;
}

export interface Question {
  id: string;
  text: string;
  options: string[];
  correctAnswer: number; // Index of the correct option
  explanation: string;
}

export interface Quiz {
  id: string;
  title: string;
  description: string;
  questions: Question[];
  difficulty: 'Easy' | 'Medium' | 'Hard';
  tags: string[];
  subject: ResourceCategory;
  chapter?: string;
  paper?: '1st' | '2nd';
  isMasterBank?: boolean;
}

export interface SocialLink {
  platform: string;
  url: string;
  icon: React.ReactNode;
}

import React, { useState, useMemo, useRef } from 'react';
import { RESOURCES, SOCIAL_LINKS, QUIZZES, SUBJECT_CHAPTERS } from './constants';
import { ResourceCategory, ResourceSubCategory, Quiz } from './types';
import ResourceCard from './components/ResourceCard';
import StudyTimer from './components/StudyTimer';
import GeminiBuddy from './components/GeminiBuddy';
import QuizCard from './components/QuizCard';
import QuizPlayer from './components/QuizPlayer';

const LabLogo: React.FC<{ className?: string }> = ({ className = "w-10 h-10" }) => (
  <svg viewBox="0 0 100 100" className={className} fill="none" xmlns="http://www.w3.org/2000/svg">
    <defs>
      <linearGradient id="logoGrad" x1="0%" y1="0%" x2="100%" y2="100%">
        <stop offset="0%" className="logo-gradient-svg" />
        <stop offset="100%" className="logo-gradient-svg-end" />
      </linearGradient>
    </defs>
    <path d="M40 30h20M45 30v15L25 80h50L55 45v-15" stroke="url(#logoGrad)" strokeWidth="3" strokeLinecap="round" />
    <ellipse cx="50" cy="40" rx="20" ry="5" stroke="url(#logoGrad)" strokeWidth="1" opacity="0.6" className="animate-pulse" />
    <ellipse cx="50" cy="35" rx="15" ry="3" stroke="url(#logoGrad)" strokeWidth="1" opacity="0.4" />
    <path d="M45 15h15l-10 10h10L45 40l5-10H40l10-15z" fill="url(#logoGrad)" className="animate-bounce" style={{ animationDuration: '3s' }} />
    <circle cx="50" cy="65" r="2" fill="url(#logoGrad)" opacity="0.8" />
    <circle cx="42" cy="72" r="1.5" fill="url(#logoGrad)" opacity="0.6" />
    <circle cx="58" cy="75" r="1" fill="url(#logoGrad)" opacity="0.4" />
  </svg>
);

const App: React.FC = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedSubject, setSelectedSubject] = useState<ResourceCategory | 'All'>('All');
  const [selectedPaper, setSelectedPaper] = useState<'1st' | '2nd' | null>(null);
  const [selectedChapter, setSelectedChapter] = useState<string>('All');
  const [selectedSubCategory, setSelectedSubCategory] = useState<ResourceSubCategory>('Quiz');
  const [activeQuiz, setActiveQuiz] = useState<Quiz | null>(null);
  const chapterScrollRef = useRef<HTMLDivElement>(null);

  const subjects: (ResourceCategory | 'All')[] = [
    'All', 'Physics', 'Chemistry', 'Biology', 'Math', 'Bangla', 'English', 'ICT'
  ];

  const subCategories: ResourceSubCategory[] = ['Quiz', 'Formula', 'Blog', 'Lit hack'];

  const filteredResources = useMemo(() => {
    return RESOURCES.filter(res => {
      const matchesSearch = res.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            res.tags.some(t => t.toLowerCase().includes(searchTerm.toLowerCase()));
      const matchesSubject = selectedSubject === 'All' || res.category === selectedSubject;
      const matchesPaper = selectedSubject === 'All' || selectedSubject === 'ICT' || !selectedPaper || res.paper === selectedPaper;
      const matchesChapter = selectedSubject === 'All' || selectedChapter === 'All' || res.chapter === selectedChapter;
      const matchesSubCategory = selectedSubject === 'All' || res.subCategory === selectedSubCategory;
      return matchesSearch && matchesSubject && matchesPaper && matchesChapter && matchesSubCategory;
    });
  }, [searchTerm, selectedSubject, selectedPaper, selectedChapter, selectedSubCategory]);

  const filteredQuizzes = useMemo(() => {
    if (selectedSubject !== 'All' && selectedSubCategory !== 'Quiz') return [];

    return QUIZZES.filter(quiz => {
      const matchesSearch = quiz.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            quiz.tags.some(t => t.toLowerCase().includes(searchTerm.toLowerCase()));
      const matchesSubject = selectedSubject === 'All' || quiz.subject === selectedSubject;
      const matchesPaper = selectedSubject === 'All' || selectedSubject === 'ICT' || !selectedPaper || quiz.paper === selectedPaper;
      const matchesChapter = selectedSubject === 'All' || selectedChapter === 'All' || quiz.chapter === selectedChapter;
      return matchesSearch && matchesSubject && matchesPaper && matchesChapter;
    });
  }, [searchTerm, selectedSubject, selectedPaper, selectedChapter, selectedSubCategory]);

  const handleSubjectClick = (subject: ResourceCategory | 'All') => {
    setSelectedSubject(subject);
    setSelectedChapter('All');
    setSelectedPaper(subject === 'ICT' || subject === 'All' ? null : '1st');
    if (subject !== 'All') {
        setSelectedSubCategory('Quiz'); 
    }
  };

  const currentChapters = useMemo(() => {
    if (selectedSubject === 'All') return [];
    const config = SUBJECT_CHAPTERS[selectedSubject];
    if (!config) return [];

    if (Array.isArray(config)) {
      return ['All', ...config];
    } else {
      const paper = selectedPaper || '1st';
      return ['All', ...(config[paper] || [])];
    }
  }, [selectedSubject, selectedPaper]);

  const startMasterPractice = () => {
    if (selectedSubject === 'All' || selectedChapter === 'All') return;
    const masterQuiz: Quiz = {
      id: `master-${selectedSubject}-${selectedChapter}-${selectedPaper || 'na'}`,
      title: `${selectedChapter} - 500+ MCQ Master Bank`,
      description: `অধ্যায়: ${selectedChapter}। এখানে বোর্ড স্ট্যান্ডার্ড ৫০০+ এমসিকিউ প্র্যাকটিস করতে পারবে AI এর সাহায্যে।`,
      difficulty: 'Hard',
      subject: selectedSubject as ResourceCategory,
      chapter: selectedChapter,
      paper: selectedPaper || undefined,
      isMasterBank: true,
      questions: [], 
      tags: [selectedSubject, selectedChapter, 'MasterBank']
    };
    setActiveQuiz(masterQuiz);
  };

  return (
    <div className="min-h-screen pb-20 selection:bg-[#00f3ff] selection:text-black">
      <div className="fixed inset-0 pointer-events-none opacity-20 overflow-hidden">
        <div className="absolute top-[-5%] left-[-5%] w-[50%] h-[50%] bg-[#00f3ff] rounded-full blur-[160px]"></div>
        <div className="absolute bottom-[-5%] right-[-5%] w-[50%] h-[50%] bg-[#bc13fe] rounded-full blur-[160px]"></div>
      </div>

      <header className="sticky top-0 z-40 bg-black/70 backdrop-blur-2xl border-b border-[#00f3ff]/10">
        <div className="max-w-7xl mx-auto px-4 h-24 flex items-center justify-between">
          <div className="flex items-center cursor-pointer" onClick={() => {setSelectedSubject('All'); setSearchTerm('');}}>
            <LabLogo className="w-12 h-12 drop-shadow-[0_0_10px_rgba(0,243,255,0.5)]" />
          </div>

          <div className="flex-1 flex justify-center text-center">
            <div>
              <h1 className="font-orbitron font-bold text-xl md:text-3xl tracking-tighter neon-text-gradient">
                ZOOMER'S <span className="text-white">LIT LAB</span>
              </h1>
              <p className="text-[10px] text-[#00f3ff]/60 uppercase tracking-[0.4em] font-bold italic hidden md:block">Lab-Powered Learning Station</p>
            </div>
          </div>

          <div className="flex items-center space-x-6">
            <div className="hidden lg:block relative group">
              <input 
                type="text" 
                placeholder="Search..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="bg-gray-900/40 border border-[#00f3ff]/20 rounded-xl px-4 py-2 pl-10 text-xs text-[#00f3ff] focus:outline-none focus:border-[#bc13fe] w-48 transition-all backdrop-blur-sm"
              />
              <svg className="absolute left-3 top-2.5 w-3.5 h-3.5 text-[#00f3ff]/40 group-focus-within:text-[#bc13fe]" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
              </svg>
            </div>

            <div className="flex items-center space-x-4">
              {SOCIAL_LINKS.map(social => (
                <a key={social.platform} href={social.url} target="_blank" rel="noopener noreferrer" className="text-gray-400 hover:text-[#bc13fe] transition-all transform hover:scale-125 hover:drop-shadow-[0_0_8px_#bc13fe]">
                  {social.icon}
                </a>
              ))}
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 mt-8">
        <div className="mb-8 text-center">
            <p className="text-[10px] text-gray-500 font-orbitron uppercase tracking-[0.4em] mb-4">Select Research Subject</p>
            <div className="flex flex-wrap justify-center gap-3 md:gap-4">
            {subjects.map(subject => (
                <button
                key={subject}
                onClick={() => handleSubjectClick(subject)}
                className={`px-6 py-3 rounded-2xl font-orbitron text-xs font-bold tracking-[0.1em] transition-all border ${
                    selectedSubject === subject 
                    ? 'bg-[#00f3ff] text-black shadow-[0_0_20px_rgba(0,243,255,0.3)] border-transparent scale-105' 
                    : 'bg-black/60 text-[#00f3ff]/70 hover:text-white border-[#00f3ff]/20 hover:border-[#bc13fe]/50 hover:bg-[#bc13fe]/5'
                }`}
                >
                {subject.toUpperCase()}
                </button>
            ))}
            </div>
        </div>

        {selectedSubject !== 'All' && selectedSubject !== 'ICT' && (
          <div className="mb-8 text-center animate-fadeIn">
            <p className="text-[10px] text-gray-500 font-orbitron uppercase tracking-[0.4em] mb-4">Select Paper</p>
            <div className="inline-flex p-1 bg-black/40 border border-[#00f3ff]/10 rounded-2xl gap-2">
              <button
                onClick={() => { setSelectedPaper('1st'); setSelectedChapter('All'); }}
                className={`px-8 py-2.5 rounded-xl font-orbitron text-[11px] font-bold tracking-widest transition-all ${
                  selectedPaper === '1st'
                  ? 'bg-[#00f3ff] text-black shadow-[0_0_15px_rgba(0,243,255,0.3)]'
                  : 'text-[#00f3ff]/60 hover:text-[#00f3ff] hover:bg-white/5'
                }`}
              >
                1ST PAPER
              </button>
              <button
                onClick={() => { setSelectedPaper('2nd'); setSelectedChapter('All'); }}
                className={`px-8 py-2.5 rounded-xl font-orbitron text-[11px] font-bold tracking-widest transition-all ${
                  selectedPaper === '2nd'
                  ? 'bg-[#00f3ff] text-black shadow-[0_0_15px_rgba(0,243,255,0.3)]'
                  : 'text-[#00f3ff]/60 hover:text-[#00f3ff] hover:bg-white/5'
                }`}
              >
                2ND PAPER
              </button>
            </div>
          </div>
        )}

        {selectedSubject !== 'All' && (
          <div className="mb-8 animate-fadeIn">
            <p className="text-[10px] text-center text-gray-500 font-orbitron uppercase tracking-[0.4em] mb-4">Select Chapter</p>
            <div 
              ref={chapterScrollRef}
              className="flex overflow-x-auto scrollbar-hide space-x-3 pb-4 px-4 justify-start md:justify-center"
            >
              {currentChapters.map(chapter => (
                <button
                  key={chapter}
                  onClick={() => setSelectedChapter(chapter)}
                  className={`flex-shrink-0 px-5 py-2 rounded-xl text-[10px] font-bold font-orbitron tracking-widest border transition-all ${
                    selectedChapter === chapter
                    ? 'border-[#00f3ff] bg-[#00f3ff]/10 text-[#00f3ff] shadow-[0_0_15px_rgba(0,243,255,0.15)]'
                    : 'border-white/5 bg-black/40 text-gray-500 hover:border-[#00f3ff]/30 hover:text-[#00f3ff]'
                  }`}
                >
                  {chapter.toUpperCase()}
                </button>
              ))}
            </div>
          </div>
        )}

        {selectedSubject !== 'All' && (
            <div className="mb-10 text-center animate-fadeIn">
                <div className="inline-flex flex-wrap justify-center p-1.5 bg-black/40 border border-[#00f3ff]/10 rounded-2xl gap-2">
                    {subCategories.map(subCat => (
                        <button
                            key={subCat}
                            onClick={() => setSelectedSubCategory(subCat)}
                            className={`px-6 py-2 rounded-xl font-orbitron text-[10px] font-bold tracking-widest transition-all ${
                                selectedSubCategory === subCat
                                ? 'bg-gradient-to-r from-[#bc13fe] to-[#ff00ff] text-white shadow-lg'
                                : 'text-gray-500 hover:text-[#bc13fe] hover:bg-white/5'
                            }`}
                        >
                            {subCat.toUpperCase()}
                        </button>
                    ))}
                </div>
            </div>
        )}

        <div className="mb-8 flex items-end justify-between border-b border-white/5 pb-4">
            <div>
                <h3 className="text-2xl font-orbitron font-bold text-white uppercase tracking-tighter">
                    {selectedSubject === 'All' ? 'Latest Sequence' : `${selectedSubject} ${selectedPaper ? `/ ${selectedPaper} Paper` : ''} / ${selectedChapter} / ${selectedSubCategory}`}
                </h3>
                <p className="text-xs text-gray-500 font-medium">Found {filteredResources.length + filteredQuizzes.length} data blocks.</p>
            </div>
            {selectedSubject !== 'All' && (
                <button onClick={() => { handleSubjectClick('All'); setSelectedPaper(null); }} className="text-[10px] font-orbitron text-[#00f3ff] hover:text-white uppercase tracking-widest font-bold">
                    [ MASTER TERMINAL ]
                </button>
            )}
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {/* Special Master Bank Card for Chapters */}
          {selectedSubject !== 'All' && selectedChapter !== 'All' && selectedSubCategory === 'Quiz' && (
            <div className="cyber-card rounded-[32px] overflow-hidden flex flex-col h-full group border-[#00f3ff]/40 shadow-[0_0_30px_rgba(0,243,255,0.1)] relative">
              <div className="absolute inset-0 bg-gradient-to-br from-cyan-500/10 to-transparent pointer-events-none"></div>
              <div className="h-40 bg-black/80 p-6 flex flex-col justify-between border-b border-[#00f3ff]/20">
                <div className="flex justify-between items-start">
                  <div className="bg-cyan-500 text-black px-4 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest animate-pulse shadow-[0_0_15px_rgba(0,243,255,0.4)]">
                    Master Bank
                  </div>
                  <LabLogo className="w-8 h-8 opacity-40" />
                </div>
                <div className="z-10">
                   <p className="text-[10px] text-cyan-400 font-bold tracking-[0.3em] uppercase">500+ DYNAMIC QUESTIONS</p>
                </div>
              </div>
              <div className="p-8 flex-1 flex flex-col relative">
                <h3 className="text-xl font-orbitron font-bold text-white mb-3 group-hover:text-cyan-400 transition-colors">
                   {selectedChapter} - ৫০০০+ MCQ প্র্যাকটিস
                </h3>
                <p className="text-gray-500 text-sm mb-8 flex-1 line-clamp-2 leading-relaxed">
                  এই অধ্যায়ের সকল বোর্ড এবং এডমিশন স্ট্যান্ডার্ড এমসিকিউ এখানে প্র্যাকটিস করো। AI মডিউলটি অনবরত নতুন প্রশ্ন জেনারেট করে।
                </p>
                <button 
                  onClick={startMasterPractice}
                  className="w-full text-center py-4 bg-gradient-to-r from-cyan-600 to-cyan-400 hover:from-cyan-500 hover:to-cyan-300 rounded-2xl text-black text-[10px] font-bold uppercase tracking-[0.3em] transition-all duration-300 shadow-xl shadow-cyan-500/20"
                >
                  ENTER MASTER TERMINAL
                </button>
              </div>
            </div>
          )}

          {filteredQuizzes.map(quiz => (
            <QuizCard key={quiz.id} quiz={quiz} onStart={() => setActiveQuiz(quiz)} />
          ))}
          {filteredResources.map(resource => (
            <ResourceCard key={resource.id} resource={resource} />
          ))}
        </div>
      </main>

      <StudyTimer />
      <GeminiBuddy />
      {activeQuiz && <QuizPlayer quiz={activeQuiz} onClose={() => setActiveQuiz(null)} />}
    </div>
  );
};

export default App;

