              />
              <svg className="absolute left-3 top-2.5 w-3.5 h-3.5 text-[#00f3ff]/40 group-focus-within:text-[#bc13fe]" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
              </svg>
            </div>

            <div className="flex items-center space-x-3 md:space-x-4">
              {SOCIAL_LINKS.map(social => (
                <a key={social.platform} href={social.url} target="_blank" rel="noopener noreferrer" className="text-gray-400 hover:text-[#bc13fe] transition-all transform hover:scale-125">
                  {social.icon}
